void launchFDWT53KernelCUDA(int WIN_SX, int WIN_SY, int *in, int *out, int sx, int sy) {
    const int steps = (sy / (15 * WIN_SY)) + ((sy % (15 * WIN_SY)) ? 1 : 0);
    int gx = (sx / WIN_SX) + ((sx % WIN_SX) ? 1 : 0);
    int gy = (sy / (WIN_SY * steps)) + ((sy % (WIN_SY * steps)) ? 1 : 0);

    printf("sliding steps = %d , gx = %d , gy = %d \n", steps, gx, gy);

    dim3 blockDim(WIN_SX, 1);
    dim3 gridDim(gx * WIN_SX, gy * 1);

    cl_fdwt53Kernel<<<gridDim, blockDim>>>(in, out, sx, sy, steps, WIN_SX, WIN_SY);
    cudaDeviceSynchronize();
    printf("cl_fdwt53Kernel in launchFDW53Kernel has finished\n");
}

void memCopyCUDA(int *dest, int *src, const size_t sx, const size_t sy) {
    cudaMemcpy(dest, src, sx * sy * sizeof(int), cudaMemcpyDeviceToDevice);
}

void fdwt53CUDA(int *in, int *out, int sizeX, int sizeY, int levels) {
    if (sizeX >= 960) {
        launchFDWT53KernelCUDA(192, 8, in, out, sizeX, sizeY);
    } else if (sizeX >= 480) {
        launchFDWT53KernelCUDA(128, 8, in, out, sizeX, sizeY);
    } else {
        launchFDWT53KernelCUDA(64, 8, in, out, sizeX, sizeY);
    }

    if (levels > 1) {
        const int llSizeX = (sizeX / 2) + ((sizeX % 2) ? 1 : 0);
        const int llSizeY = (sizeY / 2) + ((sizeY % 2) ? 1 : 0);
        memCopyCUDA(in, out, llSizeX, llSizeY);
        fdwt53CUDA(in, out, llSizeX, llSizeY, levels - 1);
    }
}

