#ifdef TIMING
        gettimeofday(&tv_mem_alloc_end, NULL);
        tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
        mem_alloc_time += tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

        rgbToComponentsCUDA(cl_c_r, cl_c_g, cl_c_b, d->srcImg, d->pixWidth, d->pixHeight);

        nStage2dDWTCUDA(cl_c_r, cl_c_r_out, cl_backup, d->pixWidth, d->pixHeight, d->dwtLvls, forward);
        nStage2dDWTCUDA(cl_c_g, cl_c_g_out, cl_backup, d->pixWidth, d->pixHeight, d->dwtLvls, forward);
        nStage2dDWTCUDA(cl_c_b, cl_c_b_out, cl_backup, d->pixWidth, d->pixHeight, d->dwtLvls, forward);

#ifdef OUTPUT
        if (writeVisual) {
            writeNStage2DDWTCUDA(cl_c_r_out, d->pixWidth, d->pixHeight, d->dwtLvls, d->outFilename, ".r");
            writeNStage2DDWTCUDA(cl_c_g_out, d->pixWidth, d->pixHeight, d->dwtLvls, d->outFilename, ".g");
            writeNStage2DDWTCUDA(cl_c_b_out, d->pixWidth, d->pixHeight, d->dwtLvls, d->outFilename, ".b");
